// Placeholder for the MSW service worker. The real file is generated by
// `npx msw init public/ --save`. This stub exists so the static export path
// always has the file present (the worker registration falls through to a
// no-op message when MSW isn't initialized).
self.addEventListener("install", () => self.skipWaiting());
self.addEventListener("activate", (e) => e.waitUntil(self.clients.claim()));
